1	/**
2	 * DigitalOcean Spaces thumbnail uploader per PROJECT_BIBLE §6.
3	 *
4	 * - Uploads to: {bucket}/thumbnails/{asset_id}.jpg
5	 * - Sets Cache-Control: public, max-age=31536000, immutable
6	 * - Returns the CDN-backed public URL
7	 * - Never uses Supabase Storage
8	 * - Supports hot-reload of S3 client when DO credentials change via heartbeat config sync
9	 */
10	
11	import { S3Client, PutObjectCommand } from "@aws-sdk/client-s3";
12	import { config } from "./config.js";
13	import { logger } from "./logger.js";
14	
15	let s3Client: S3Client | null = null;
16	let currentCredentials = { key: "", secret: "", bucket: "", region: "", endpoint: "" };
17	
18	function getClient(): S3Client {
19	  if (!s3Client) {
20	    currentCredentials = {
21	      key: config.doSpacesKey,
22	      secret: config.doSpacesSecret,
23	      bucket: config.doSpacesBucket,
24	      region: config.doSpacesRegion,
25	      endpoint: config.doSpacesEndpoint,
26	    };
27	    s3Client = new S3Client({
28	      region: currentCredentials.region,
29	      endpoint: currentCredentials.endpoint,
30	      credentials: {
31	        accessKeyId: currentCredentials.key,
32	        secretAccessKey: currentCredentials.secret,
33	      },
34	      forcePathStyle: false,
35	    });
36	  }
37	  return s3Client;
38	}
39	
40	/**
41	 * Re-initialize the S3 client when Spaces config changes via heartbeat.
42	 * Key/secret are optional — if omitted, preserves existing credentials from .env.
43	 */
44	export function reinitializeS3Client(doSpaces: {
45	  key?: string;
46	  secret?: string;
47	  bucket?: string;
48	  region?: string;
49	  endpoint?: string;
50	}): boolean {
51	  // Ensure client is initialized so currentCredentials is populated
52	  getClient();
53	
54	  const effectiveKey = doSpaces.key || currentCredentials.key;
55	  const effectiveSecret = doSpaces.secret || currentCredentials.secret;
56	  const effectiveBucket = doSpaces.bucket || currentCredentials.bucket;
57	  const effectiveRegion = doSpaces.region || currentCredentials.region;
58	  const effectiveEndpoint = doSpaces.endpoint || currentCredentials.endpoint;
59	
60	  // Check if anything actually changed
61	  if (
62	    effectiveKey === currentCredentials.key &&
63	    effectiveSecret === currentCredentials.secret &&
64	    effectiveBucket === currentCredentials.bucket &&
65	    effectiveRegion === currentCredentials.region &&
66	    effectiveEndpoint === currentCredentials.endpoint
67	  ) {
68	    return false;
69	  }
70	
71	  logger.info("DO Spaces config changed — reinitializing S3 client", {
72	    bucket: effectiveBucket,
73	    region: effectiveRegion,
74	  });
75	
76	  currentCredentials = {
77	    key: effectiveKey,
78	    secret: effectiveSecret,
79	    bucket: effectiveBucket,
80	    region: effectiveRegion,
81	    endpoint: effectiveEndpoint,
82	  };
83	  s3Client = new S3Client({
84	    region: effectiveRegion,
85	    endpoint: effectiveEndpoint,
86	    credentials: {
87	      accessKeyId: effectiveKey,
88	      secretAccessKey: effectiveSecret,
89	    },
90	    forcePathStyle: false,
91	  });
92	
93	  return true;
94	}
