156	async function uploadToSpaces(key: string, buffer: Buffer, quality?: number): Promise<string> {
157	  const bucket = getCurrentBucket();
158	  const region = getCurrentRegion();
159	
160	  const client = getClient();
161	  await client.send(
162	    new PutObjectCommand({
163	      Bucket: bucket,
164	      Key: key,
165	      Body: buffer,
166	      ContentType: "image/jpeg",
167	      CacheControl: "public, max-age=31536000, immutable",
168	      ACL: "public-read",
169	    }),
170	  );
171	
172	  const url = `https://${bucket}.${region}.digitaloceanspaces.com/${key}`;
173	  logger.info("Thumbnail uploaded", { key, url });
174	  return url;
175	}
