1	/**
2	 * Realtime watcher — subscribes to admin_config Postgres Changes so the bridge
3	 * agent reacts to SCAN_REQUEST instantly instead of waiting for the next
4	 * heartbeat (up to 30s latency).
5	 *
6	 * Requires SUPABASE_ANON_KEY env var.  If absent, this is a no-op and the agent
7	 * falls back to heartbeat-only command delivery (functional, just slower).
8	 *
9	 * Security: the anon key can only see the SCAN_REQUEST row (RLS policy added in
10	 * migration 20260325120000).  That row holds only non-secret metadata: request_id,
11	 * status, requested_at, requested_by (uuid), target_agent_id.
12	 */
13	
14	import { createClient } from "@supabase/supabase-js";
15	import ws from "ws";
16	import { logger } from "./logger.js";
17	
18	// @supabase/realtime-js >= 2.11 requires globalThis.WebSocket on Node.js < 22
19	if (typeof globalThis.WebSocket === "undefined") {
20	  (globalThis as Record<string, unknown>).WebSocket = ws;
21	}
22	
23	// Keys whose pending state should trigger an immediate heartbeat rather than
24	// waiting up to 30s for the next scheduled poll.
25	const WATCHED_KEYS = ["SCAN_REQUEST", "DIR_BROWSE_REQUEST", "PATH_TEST_REQUEST"];
26	
27	export function startRealtimeWatcher(
28	  supabaseUrl: string,
29	  anonKey: string,
30	  agentId: string,
31	  onCommandPending: () => void,
32	): () => Promise<void> {
33	  if (!anonKey) {
34	    logger.info(
35	      "SUPABASE_ANON_KEY not set — Realtime watcher disabled (heartbeat-only mode, commands up to 30s delayed)",
36	    );
37	    return () => Promise.resolve();
38	  }
39	
40	  const client = createClient(supabaseUrl, anonKey, {
41	    realtime: { params: { eventsPerSecond: 2 } },
42	    auth: { persistSession: false },
43	  });
44	
45	  // Use separate eq filters per key — the `in` operator is less reliable in
46	  // Postgres Changes than chained eq subscriptions on the same channel.
47	  let channel = client.channel("agent-command-watcher");
48	  for (const watchedKey of WATCHED_KEYS) {
49	    channel = channel.on(
50	      "postgres_changes",
51	      { event: "*", schema: "public", table: "admin_config", filter: `key=eq.${watchedKey}` },
52	      (payload) => {
53	        const row = (payload.new ?? {}) as Record<string, unknown>;
54	        const key = row.key as string | undefined;
55	        const value = row.value as Record<string, unknown> | undefined;
56	        if (!value) return;
57	
58	        const status = value.status as string | undefined;
59	        const targetAgentId = value.target_agent_id as string | undefined;
60	
61	        // Only react to freshly-pending requests that target this agent (or all agents).
62	        if (status !== "pending") return;
63	        if (targetAgentId && targetAgentId !== agentId) return;
64	
65	        logger.info(`Realtime: ${key} detected — triggering immediate heartbeat`);
66	        onCommandPending();
67	      },
68	    );
69	  }
70	  channel.subscribe((status, err) => {
71	      if (status === "SUBSCRIBED") {
72	        logger.info(`Realtime watcher active — commands (${WATCHED_KEYS.join(", ")}) will be delivered instantly`);
73	      } else if (status === "CHANNEL_ERROR" || status === "TIMED_OUT") {
74	        logger.warn("Realtime watcher connection issue — falling back to heartbeat polling", {
75	          status,
76	          error: (err as Error | undefined)?.message,
77	        });
78	      }
79	    });
80	
81	  return async () => {
82	    try {
83	      await client.removeAllChannels();
84	    } catch (e) {
85	      logger.warn("Realtime cleanup error (non-fatal)", { error: (e as Error).message });
86	    }
87	  };
88	}
