87	/**
88	 * Recursively scan directories and yield file candidates.
89	 * Per WORKER_LOGIC §4.2: do NOT follow symlinks.
90	 */
91	export interface ScanCallbacks {
92	  shouldAbort?: () => boolean;
93	  onDir?: (dirPath: string) => void;
94	  onSkippedDir?: (dirPath: string, reason: string) => void;
95	}
96	
97	export async function* scanFiles(
98	  counters: Counters,
99	  scanRoots?: string[],
100	  callbacks?: ScanCallbacks,
101	  resumeFromDir?: string,
102	  mountRoot?: string,
103	): AsyncGenerator<FileCandidate> {
104	  resetSkipWarnings(); // Reset per-session dedup for skip warnings
105	  const roots = scanRoots ?? config.scanRoots;
106	  const effectiveMountRoot = mountRoot || config.nasContainerMountRoot;
107	  for (const root of roots) {
108	    if (callbacks?.shouldAbort?.()) return;
109	    yield* scanDirectory(root, counters, callbacks, root, resumeFromDir, effectiveMountRoot);
110	  }
111	}
112	
113	async function* scanDirectory(
114	  dirPath: string,
115	  counters: Counters,
116	  callbacks?: ScanCallbacks,
117	  scanRoot?: string,
118	  resumeFromDir?: string,
119	  mountRoot?: string,
120	): AsyncGenerator<FileCandidate> {
121	  if (callbacks?.shouldAbort?.()) return;
122	  let entries;
123	  try {
124	    entries = await readdir(dirPath, { withFileTypes: true });
125	    callbacks?.onDir?.(dirPath);
126	  } catch (e) {
127	    const code = (e as NodeJS.ErrnoException).code;
128	    if (code === "EACCES") {
129	      counters.dirs_skipped_permission++;
130	      logger.warn("Directory not readable, skipping", { dirPath });
131	      callbacks?.onSkippedDir?.(dirPath, "EACCES");
132	    } else {
133	      logger.warn("Failed to read directory", { dirPath, error: (e as Error).message });
134	      callbacks?.onSkippedDir?.(dirPath, code || "unknown");
135	    }
136	    return;
137	  }
138	
139	  // Build a set of lowercased PDF basenames in this directory so we can skip
140	  // .ai files that have a same-named .pdf sibling (PDF is the canonical form).
141	  const pdfBasenames = new Set(
142	    entries
143	      .filter((e) => extname(e.name).toLowerCase() === ".pdf")
144	      .map((e) => e.name.toLowerCase().replace(/\.[^.]+$/, "")),
145	  );
146	
147	  for (const entry of entries) {
148	    if (callbacks?.shouldAbort?.()) return;
149	
150	    const fullPath = join(dirPath, entry.name);
151	
152	    // §4.2: Do NOT follow symlinks
153	    try {
154	      const ls = await lstat(fullPath);
155	      if (ls.isSymbolicLink()) continue;
156	    } catch {
157	      counters.files_stat_failed++;
158	      continue;
159	    }
160	
161	    if (entry.isDirectory()) {
162	      // Skip excluded directories using centralized path-filters
163	      if (shouldSkipFolder(entry.name)) {
164	        logger.debug("Skipping excluded directory", { dirPath: fullPath, folder: entry.name });
165	        counters.dirs_skipped_excluded++;
166	        continue;
167	      }
168	
169	      // Resume support: if resumeFromDir is set and this is a top-level
170	      // subdirectory (one level below scan root), skip dirs that sort before it
171	      if (resumeFromDir && scanRoot && dirPath === scanRoot) {
172	        if (fullPath < resumeFromDir) {
173	          logger.debug("Skipping already-checkpointed directory", { dir: fullPath, resumeFrom: resumeFromDir });
174	          continue;
175	        }
176	      }
177	      yield* scanDirectory(fullPath, counters, callbacks, scanRoot, resumeFromDir, mountRoot);
178	      continue;
179	    }
180	
181	    if (!entry.isFile()) continue;
182	
183	    counters.files_total_encountered++;
184	
185	    const ext = extname(entry.name).toLowerCase();
186	    if (!SUPPORTED_EXTENSIONS.has(ext)) {
187	      const name = entry.name;
188	      const JUNK_FILENAMES = new Set([".DS_Store", ".localized", "Thumbs.db", "desktop.ini"]);
189	      if (
190	        name.startsWith("._") ||
191	        name.startsWith("~") ||
192	        JUNK_FILENAMES.has(name) ||
193	        dirPath.includes("__MACOSX")
194	      ) {
195	        counters.rejected_junk_file++;
196	      } else {
197	        counters.rejected_wrong_type++;
198	      }
199	      continue;
200	    }
201	
202	    // Check full path for excluded segments (catches files nested inside excluded dirs)
203	    if (shouldSkipPath(fullPath, logger.warn)) {
204	      counters.rejected_junk_file++;
205	      continue;
206	    }
207	
208	    // PDF keyword filter: only accept PDFs matching specific document types
209	    if (ext === ".pdf" && !isPdfCandidate(entry.name)) {
210	      counters.rejected_wrong_type++;
211	      continue;
212	    }
213	
214	    // Skip .ai files when a same-named .pdf sibling exists in the same directory.
215	    // The PDF is the canonical distributable; the .ai is the editable source.
216	    if (ext === ".ai") {
217	      const aiBase = entry.name.toLowerCase().replace(/\.[^.]+$/, "");
218	      if (pdfBasenames.has(aiBase)) {
219	        counters.rejected_ai_has_pdf_sibling++;
220	        logger.debug("Skipping .ai with .pdf sibling", { file: fullPath });
221	        continue;
222	      }
223	    }
224	
225	    counters.files_checked++;
226	
227	    try {
228	      const s = await stat(fullPath);
229	
230	      // Build canonical relative path (POSIX, no leading slash) per PATH_UTILS.md §1
231	      const effectiveRoot = mountRoot || config.nasContainerMountRoot;
232	      let relPath = relative(effectiveRoot, fullPath);
233	      relPath = relPath.split("\\").join("/"); // Ensure POSIX
234	      if (relPath.startsWith("/")) relPath = relPath.slice(1);
235	
236	      const fileType: "psd" | "ai" | "pdf" = ext === ".psd" ? "psd" : ext === ".ai" ? "ai" : "pdf";
237	
238	      const candidate: FileCandidate = {
239	        absolutePath: fullPath,
240	        relativePath: relPath,
241	        filename: basename(entry.name),
242	        fileType,
243	        fileSize: s.size,
244	        // modifiedAt = mtime (last content modification, NOT access time)
245	        // fileCreatedAt = birthtime (original creation time, may be null on Linux)
246	        // We intentionally do NOT use atime (last access time) as it changes on read
247	        modifiedAt: s.mtime,
248	        fileCreatedAt: s.birthtime?.getFullYear() > 1970 ? s.birthtime : null,
249	      };
250	
251	      counters.candidates_found++;
252	      yield candidate;
253	    } catch (e) {
254	      counters.files_stat_failed++;
255	      logger.warn("Failed to stat file", { fullPath, error: (e as Error).message });
256	    }
257	  }
258	}
