10	async function getHeaders(): Promise<Record<string, string>> {
11	  const session = await loadSession();
12	  const headers: Record<string, string> = {
13	    "Content-Type": "application/json",
14	  };
15	  if (session?.accessToken) {
16	    headers["Authorization"] = `Bearer ${session.accessToken}`;
17	  }
