21	function apiUrl(path: string): string {
22	  const { supabaseUrl, damUrl } = getConfig();
23	  // supabaseUrl is the Supabase project URL (e.g. https://xyz.supabase.co)
24	  // discovered from ${damUrl}/dam-config.json on first setup.
25	  const base = (supabaseUrl || damUrl).replace(/\/$/, "");
26	  return `${base}/functions/v1/helper-api${path}`;
