29	export async function discoverSupabaseConfig(damUrl: string): Promise<{ supabaseUrl: string; supabaseAnonKey: string }> {
30	  const base = damUrl.replace(/\/$/, "");
31	  const res = await fetch(`${base}/dam-config.json`);
32	  if (!res.ok) throw new Error(`Could not fetch dam-config.json (${res.status})`);
33	  const json = await res.json();
34	  if (!json.supabase_url) throw new Error("dam-config.json missing supabase_url");
35	  return {
36	    supabaseUrl: json.supabase_url as string,
37	    supabaseAnonKey: (json.supabase_anon_key ?? "") as string,
