41	async function post<T>(path: string, body: unknown): Promise<T> {
42	  const url = apiUrl(path);
43	  log.debug("POST", url);
44	  const res = await fetch(url, {
45	    method: "POST",
46	    headers: await getHeaders(),
47	    body: JSON.stringify(body),
48	  });
49	  if (!res.ok) {
50	    const text = await res.text().catch(() => res.statusText);
51	    throw new Error(`POST ${path} failed (${res.status}): ${text}`);
52	  }
53	  return res.json();
54	}
