56	async function get<T>(path: string): Promise<T> {
57	  const url = apiUrl(path);
58	  log.debug("GET", url);
59	  const res = await fetch(url, {
60	    method: "GET",
61	    headers: await getHeaders(),
62	  });
63	  if (!res.ok) {
64	    const text = await res.text().catch(() => res.statusText);
65	    throw new Error(`GET ${path} failed (${res.status}): ${text}`);
66	  }
67	  return res.json();
68	}
