25	async function getUserId(req: Request): Promise<string | null> {
26	  const auth = req.headers.get("Authorization");
27	  if (!auth?.startsWith("Bearer ")) return null;
28	  const token = auth.slice(7);
29	  const client = createClient(
30	    Deno.env.get("SUPABASE_URL")!,
31	    Deno.env.get("SUPABASE_ANON_KEY")!,
32	  );
33	  const { data: { user }, error } = await client.auth.getUser(token);
34	  if (error || !user) return null;
35	  return user.id;
36	}
