46	async function handleRegisterDevice(req: Request): Promise<Response> {
47	  const userId = await getUserId(req);
48	  if (!userId) return err("Unauthorized", 401);
49	
50	  const body = await req.json();
51	  const { device_name, device_os, helper_version, device_id } = body;
52	  if (!device_name || !device_os || !helper_version) {
53	    return err("Missing required fields: device_name, device_os, helper_version");
54	  }
55	  if (!["windows", "macos"].includes(device_os)) {
56	    return err("device_os must be 'windows' or 'macos'");
57	  }
58	
59	  const db = serviceClient();
60	
61	  if (device_id) {
62	    // Update existing device
63	    const { data, error } = await db
64	      .from("helper_devices")
65	      .update({ device_name, helper_version, last_seen_at: new Date().toISOString() })
66	      .eq("id", device_id)
67	      .eq("user_id", userId)
68	      .select("id")
69	      .single();
70	    if (error || !data) {
71	      // Not found — fall through to insert
72	    } else {
73	      return json({ ok: true, device_id: data.id });
74	    }
75	  }
76	
77	  // Insert new device
78	  const { data, error } = await db
79	    .from("helper_devices")
80	    .insert({ user_id: userId, device_name, device_os, helper_version })
81	    .select("id")
82	    .single();
83	  if (error) return err(`Failed to register device: ${error.message}`, 500);
84	  return json({ ok: true, device_id: data.id });
85	}
