87	async function handleGetConfig(_req: Request): Promise<Response> {
88	  // No user auth required — root mappings are the same for all users and not sensitive.
89	  // The Supabase anon key (enforced by the edge function invocation layer) is sufficient.
90	  const db = serviceClient();
91	
92	  // Load config from admin_config — root_mappings derived from SCAN_ROOTS (same source the bridge agent uses)
93	  const { data: rows } = await db
94	    .from("admin_config")
95	    .select("key, value")
96	    .in("key", [
97	      "SCAN_ROOTS",
98	      "HELPER_SYNOLOGY_URL",
99	      "HELPER_SYNOLOGY_PORT",
100	      "HELPER_DAM_URL",
101	      "HELPER_SEAFILE_PREFERRED",
102	      "HELPER_SEAFILE_LIBRARIES",
103	      "HELPER_SEAFILE_SERVER_URL",
104	      "HELPER_SYNOLOGY_FALLBACK_ALLOWED",
105	    ]);
106	
107	  const cfg: Record<string, unknown> = {};
108	  for (const row of rows ?? []) {
109	    cfg[row.key] = row.value;
110	  }
111	
112	  const scanRoots: string[] = Array.isArray(cfg["SCAN_ROOTS"]) ? (cfg["SCAN_ROOTS"] as string[]) : [];
113	  const rootMappings = scanRoots.map((r) => {
114	    const name = r.replace(/\/+$/, "").split("/").pop() || r;
115	    return { root_id: name, display_name: name, server_path: r };
116	  });
117	
118	  // HELPER_SEAFILE_LIBRARIES is stored as a JSON string (array of mappings).
119	  let seafileLibraries: unknown[] = [];
120	  const rawLibs = cfg["HELPER_SEAFILE_LIBRARIES"];
121	  if (Array.isArray(rawLibs)) {
122	    seafileLibraries = rawLibs;
123	  } else if (typeof rawLibs === "string" && rawLibs.trim()) {
124	    try {
125	      const parsed = JSON.parse(rawLibs);
126	      if (Array.isArray(parsed)) seafileLibraries = parsed;
127	    } catch {
128	      // malformed config — return empty rather than failing the whole request
129	    }
130	  }
131	
132	  const truthy = (v: unknown) => v === true || v === "true";
133	
134	  return json({
135	    ok: true,
136	    dam_url: (cfg["HELPER_DAM_URL"] as string) ?? null,
137	    synology_url: (cfg["HELPER_SYNOLOGY_URL"] as string) ?? null,
138	    synology_port: (cfg["HELPER_SYNOLOGY_PORT"] as string) ?? "5001",
139	    root_mappings: rootMappings,
140	    // ── Seafile config (no secrets here — API tokens stay client-side) ──
141	    seafile_preferred: truthy(cfg["HELPER_SEAFILE_PREFERRED"]),
142	    synology_fallback_allowed: truthy(cfg["HELPER_SYNOLOGY_FALLBACK_ALLOWED"]),
143	    seafile_server_url: (cfg["HELPER_SEAFILE_SERVER_URL"] as string) ?? null,
144	    seafile_libraries: seafileLibraries,
145	  });
146	}
