148	async function handleCreateToken(req: Request): Promise<Response> {
149	  const userId = await getUserId(req);
150	  if (!userId) return err("Unauthorized", 401);
151	
152	  const body = await req.json();
153	  const { action, asset_id, checkout_id } = body;
154	
155	  if (!action || !["checkout", "checkin", "open", "reveal", "discard"].includes(action)) {
156	    return err("Invalid action");
157	  }
158	  if (action === "checkout" && !asset_id) return err("asset_id required for checkout");
159	  if (["checkin", "open", "reveal", "discard"].includes(action) && !checkout_id && !asset_id) {
160	    return err("checkout_id or asset_id required");
161	  }
162	
163	  const db = serviceClient();
164	
165	  // For checkout, verify asset exists and is not already locked
166	  if (action === "checkout" && asset_id) {
167	    const { data: asset } = await db
168	      .from("assets")
169	      .select("id, filename, relative_path, quick_hash, file_size")
170	      .eq("id", asset_id)
171	      .eq("is_deleted", false)
172	      .single();
173	    if (!asset) return err("Asset not found or deleted");
174	
175	    const { data: existing } = await db
176	      .from("asset_checkouts")
177	      .select("id, user_id")
178	      .eq("asset_id", asset_id)
179	      .in("status", ["active", "checkin_queued", "uploading", "verifying"])
180	      .maybeSingle();
181	
182	    if (existing && existing.user_id !== userId) {
183	      return err("Asset is currently checked out by another user", 409);
184	    }
185	  }
186	
187	  const tokenId = randomHex(16); // 32 hex chars
188	  const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString(); // 5 minutes
189	
190	  const { error } = await db.from("helper_tokens").insert({
191	    id: tokenId,
192	    user_id: userId,
193	    action,
