1	/**
2	 * Seafile / SeaDrive adapter.
3	 *
4	 * The Helper *supervises* an officially-installed SeaDrive client — it never
5	 * forks, embeds, or writes into the shared mount as the primary workflow.
6	 * Everything here is read-only detection + path mapping + hydration waiting.
7	 *
8	 * Boundary (see docs/POPDAM_HELPER.md / HANDOFF.md):
9	 *  - Detect the installed client and its mount root.
10	 *  - Map a PopDAM root_id + relative_path to a SeaDrive library path.
11	 *  - Confirm a file is hydrated (fully local) or trigger + wait for hydration.
12	 *  - Optionally fetch the Seafile REST `obj_id` for source_version (needs a token).
13	 *
14	 * No API token required for the first slice: getSeafileObjId() returns null
15	 * when no token/server URL is configured, which is an accepted state.
16	 */
17	
18	import { existsSync, statSync, openSync, closeSync, readSync } from "fs";
19	import { join, normalize, isAbsolute, sep } from "path";
20	import { homedir } from "os";
21	import { execFileSync } from "child_process";
22	import { loadToken } from "./credentials";
23	import { log } from "./logger";
24	import type {
25	  LocalConfig,
26	  SeafileLibraryMapping,
27	  StorageHealth,
28	  HydrationStatus,
29	} from "@shared/types";
30	
31	// ── Mount-root detection ────────────────────────────────────────────────────
32	
33	/**
34	 * Resolve the SeaDrive mount root. Order:
35	 *  1. Explicit config.seaDriveRoot (user override / previously detected).
36	 *  2. Platform default (~/SeaDrive on macOS, %USERPROFILE%\SeaDrive on Windows).
37	 * Returns the path only if it exists on disk; otherwise null.
38	 */
39	export function detectSeaDriveRoot(config: LocalConfig): string | null {
40	  const candidates: string[] = [];
41	  if (config.seaDriveRoot) candidates.push(config.seaDriveRoot);
42	  candidates.push(join(homedir(), "SeaDrive"));
43	
44	  for (const c of candidates) {
45	    try {
46	      if (existsSync(c) && statSync(c).isDirectory()) return c;
47	    } catch {
48	      /* ignore */
49	    }
50	  }
51	  return null;
52	}
53	
54	// ── Install / process detection ─────────────────────────────────────────────
55	
56	/**
57	 * Best-effort check for an installed SeaDrive (virtual-drive) client.
58	 * We only support SeaDrive — never the legacy Seafile *sync* client, which would
59	 * try to fully download a library to local disk. Do not add sync-client paths here.
60	 */
61	export function isSeaDriveInstalled(): boolean {
62	  const paths =
63	    process.platform === "darwin"
64	      ? [
65	          "/Applications/SeaDrive.app",
66	          join(homedir(), "Applications/SeaDrive.app"),
67	        ]
68	      : [
69	          "C:\\Program Files\\SeaDrive\\seadrive.exe",
70	          "C:\\Program Files (x86)\\SeaDrive\\seadrive.exe",
71	        ];
72	  return paths.some((p) => {
73	    try {
74	      return existsSync(p);
75	    } catch {
76	      return false;
77	    }
78	  });
79	}
80	
81	/** Best-effort process-list check. Never throws — returns false on any error. */
82	export function isSeaDriveRunning(): boolean {
83	  try {
84	    if (process.platform === "darwin") {
85	      // pgrep exits non-zero (throws) when nothing matches.
86	      const out = execFileSync("pgrep", ["-il", "seadrive"], {
87	        encoding: "utf-8",
88	        timeout: 3000,
89	      });
90	      return out.trim().length > 0;
91	    }
92	    // Windows
93	    const out = execFileSync(
94	      "tasklist",
95	      ["/FI", "IMAGENAME eq seadrive.exe", "/NH"],
96	      { encoding: "utf-8", timeout: 3000 },
97	    );
98	    return /seadrive\.exe/i.test(out);
99	  } catch {
100	    return false;
101	  }
102	}
