150	
151	export interface SeafileTarget {
152	  mapping: SeafileLibraryMapping;
153	  localPath: string;  // absolute path under the SeaDrive mount
154	  pathInLib: string;  // path within the Seafile library (relative_path minus the prefix)
155	}
156	
157	/**
158	 * Resolve a PopDAM relative_path to a SeaDrive target: the matching library,
159	 * the absolute local path, and the in-library path.
160	 *
161	 * Throws on: no mount root, no library covering the path, or unsafe path.
162	 */
163	export function resolveSeafileTarget(
164	  relativePath: string,
165	  config: LocalConfig,
166	): SeafileTarget {
167	  const root = detectSeaDriveRoot(config);
168	  if (!root) throw new Error("SeaDrive mount root not found.");
169	
170	  const mapping = findMappingForPath(relativePath, config);
171	  if (!mapping) {
172	    throw new Error(`No Seafile library covers "${relativePath}".`);
173	  }
174	
175	  const rel = normalizeRel(relativePath);
176	  const prefix = normalizeRel(mapping.pathPrefix);
177	  const remainder = rel === prefix ? "" : rel.slice(prefix.length + 1);
178	  const pathInLib = remainder ? sanitizeRelativePath(remainder) : "";
179	  const localPath = pathInLib
180	    ? join(root, mapping.seaDriveFolder, pathInLib)
181	    : join(root, mapping.seaDriveFolder);
182	  return { mapping, localPath, pathInLib };
183	}
184	
185	/** Convenience wrapper returning just the absolute local path. */
186	export function resolveSeafilePath(relativePath: string, config: LocalConfig): string {
187	  return resolveSeafileTarget(relativePath, config).localPath;
188	}
189	
190	/** Library folders that are actually present (mounted) under the SeaDrive root. */
191	export function getMountedLibraries(config: LocalConfig): string[] {
192	  const root = detectSeaDriveRoot(config);
193	  if (!root) return [];
194	  return (config.seafileLibraries ?? [])
195	    .map((m) => m.seaDriveFolder)
196	    .filter((folder) => {
197	      try {
198	        return existsSync(join(root, folder));
199	      } catch {
200	        return false;
201	      }
202	    });
