247	/**
248	 * SeaDrive presents cloud-only files as zero-byte (or sparse) placeholders that
249	 * fill in on access. We treat a readable, non-empty, size-stable file as local.
250	 */
251	export function getHydrationStatus(localPath: string): HydrationStatus {
252	  try {
253	    if (!existsSync(localPath)) return { state: "unavailable" };
254	    const size = statSync(localPath).size;
255	    if (size <= 0) return { state: "hydrating", bytesDone: 0 };
256	    return { state: "local", bytesDone: size, bytesTotal: size };
257	  } catch {
258	    return { state: "unavailable" };
259	  }
260	}
261	
262	/** Touch the file to nudge SeaDrive into hydrating it (read first byte). */
263	function nudgeHydration(localPath: string): void {
264	  try {
265	    const fd = openSync(localPath, "r");
266	    try {
267	      const buf = Buffer.alloc(1);
268	      readSync(fd, buf, 0, 1, 0);
269	    } finally {
270	      closeSync(fd);
271	    }
272	  } catch {
273	    /* best-effort */
274	  }
275	}
