277	/**
278	 * Ensure a SeaDrive file is fully local. Triggers hydration and polls until the
279	 * size is stable across two reads. Throws if it never stabilizes in time.
280	 */
281	export async function ensureHydrated(
282	  localPath: string,
283	  opts: { maxAttempts?: number; intervalMs?: number; onProgress?: (s: HydrationStatus) => void } = {},
284	): Promise<void> {
285	  const maxAttempts = opts.maxAttempts ?? 60; // ~3 min at 3s
286	  const intervalMs = opts.intervalMs ?? 3000;
287	
288	  if (!existsSync(localPath)) {
289	    throw new Error(`File not found in SeaDrive: ${localPath}`);
290	  }
291	
292	  nudgeHydration(localPath);
293	
294	  let lastSize = -1;
295	  let stable = 0;
296	  for (let i = 0; i < maxAttempts; i++) {
297	    const status = getHydrationStatus(localPath);
298	    opts.onProgress?.(status);
299	    if (status.state === "local") {
300	      const size = status.bytesDone ?? 0;
301	      if (size === lastSize) {
302	        stable++;
303	        if (stable >= 2) return;
304	      } else {
305	        stable = 0;
306	        lastSize = size;
307	      }
308	    } else if (status.state === "unavailable") {
309	      throw new Error(`File became unavailable during hydration: ${localPath}`);
310	    } else {
311	      stable = 0;
312	      nudgeHydration(localPath);
313	    }
314	    await sleep(intervalMs);
315	  }
316	  throw new Error(
317	    `File "${localPath}" did not finish hydrating from SeaDrive in time.`,
318	  );
319	}
