151	async function renameFile(
152	  config: SynologyConfig,
153	  sid: string,
154	  folder: string,
155	  oldName: string,
156	  newName: string,
157	): Promise<void> {
158	  const url = `${apiBase(config)}/entry.cgi`;
159	  const body = new URLSearchParams({
160	    api: "SYNO.FileStation.Rename",
161	    version: "2",
162	    method: "rename",
163	    path: JSON.stringify([`${folder}/${oldName}`]),
164	    name: JSON.stringify([newName]),
165	    _sid: sid,
166	  });
167	
168	  const res = await fetch(url, {
169	    method: "POST",
170	    body,
171	    headers: { "Content-Type": "application/x-www-form-urlencoded" },
172	  });
173	  const json = await res.json();
174	  if (!json.success) {
175	    throw new Error(`Synology rename failed: error code ${json.error?.code}`);
176	  }
177	}
