181	export async function downloadFile(
182	  config: SynologyConfig,
183	  shareName: string,
184	  remotePath: string,
185	  localDestPath: string,
186	): Promise<void> {
187	  const sid = await login(config);
188	  const fullRemotePath = `/${shareName}/${remotePath}`.replace(/\/\//g, "/");
189	
190	  const url =
191	    `${apiBase(config)}/entry.cgi` +
192	    `?api=SYNO.FileStation.Download&version=2&method=download` +
193	    `&path=${encodeURIComponent(fullRemotePath)}&mode=download&_sid=${sid}`;
194	
195	  const res = await fetch(url);
196	  if (!res.ok) throw new Error(`Synology download failed: ${res.status}`);
