198	  mkdirSync(dirname(localDestPath), { recursive: true });
199	
200	  const buf = Buffer.from(await res.arrayBuffer());
201	  writeFileSync(localDestPath, buf);
202	  log.info(`Downloaded ${fullRemotePath} → ${localDestPath}`);
203	}
