2	 * Background upload queue — persisted to userData/upload-queue.json.
3	 * Uploads snapshots to Synology asynchronously so the user can keep working.
4	 * Pure JSON file store — no native modules needed.
5	 */
6	
7	import { app } from "electron";
8	import { join, dirname } from "path";
9	import { existsSync, readFileSync, writeFileSync, mkdirSync } from "fs";
10	import { log } from "./logger";
11	import { loadToken } from "./credentials";
12	import { uploadFile } from "./synologyClient";
13	import { completeCheckin } from "./damClient";
14	import { sha256File } from "./hash";
15	import { statSync } from "fs";
16	import { UPLOAD_MAX_RETRIES, UPLOAD_RETRY_DELAY_MS } from "@shared/constants";
17	import type { UploadJob } from "@shared/types";
18	
19	interface StoredJob extends UploadJob {
20	  status: "pending" | "uploading" | "failed";
21	  lastAttempt: number | null;
22	}
23	
24	let queuePath: string;
25	let running = false;
26	let progressCallback: ((checkoutId: string, percent: number) => void) | null = null;
27	
28	// ── Init ──────────────────────────────────────────────────────────────────────
29	
30	export function initQueue(): void {
31	  queuePath = join(app.getPath("userData"), "upload-queue.json");
32	}
33	
34	export function setProgressCallback(cb: (checkoutId: string, percent: number) => void): void {
35	  progressCallback = cb;
36	}
37	
38	// ── Persistence helpers ───────────────────────────────────────────────────────
39	
40	function readJobs(): StoredJob[] {
41	  try {
42	    return JSON.parse(readFileSync(queuePath, "utf-8"));
43	  } catch {
44	    return [];
45	  }
46	}
47	
48	function writeJobs(jobs: StoredJob[]): void {
49	  mkdirSync(dirname(queuePath), { recursive: true });
50	  writeFileSync(queuePath, JSON.stringify(jobs, null, 2), "utf-8");
51	}
52	
53	// ── Enqueue ───────────────────────────────────────────────────────────────────
54	
55	export function enqueue(job: UploadJob): void {
56	  const jobs = readJobs();
57	  const existing = jobs.findIndex((j) => j.checkoutId === job.checkoutId);
58	  const stored: StoredJob = { ...job, status: "pending", lastAttempt: null };
59	  if (existing >= 0) {
60	    jobs[existing] = stored;
61	  } else {
62	    jobs.push(stored);
63	  }
64	  writeJobs(jobs);
65	  log.info(`Enqueued upload for checkout ${job.checkoutId}`);
66	  if (!running) processQueue();
67	}
68	
69	// ── Process ───────────────────────────────────────────────────────────────────
70	
71	export async function processQueue(): Promise<void> {
72	  if (running) return;
73	  running = true;
74	
75	  try {
76	    while (true) {
77	      const jobs = readJobs();
78	      const job = jobs.find(
79	        (j) => j.status === "pending" && j.retryCount < UPLOAD_MAX_RETRIES,
80	      );
81	      if (!job) break;
82	      await processJob(job);
83	    }
84	  } finally {
85	    running = false;
86	  }
87	}
88	
89	async function processJob(job: StoredJob): Promise<void> {
90	  const { checkoutId, snapshotPath } = job;
91	  log.info(`Processing upload job for checkout ${checkoutId}`);
92	
93	  updateJob(checkoutId, { status: "uploading", lastAttempt: Date.now() });
94	
95	  try {
96	    if (!existsSync(snapshotPath)) {
97	      throw new Error(`Snapshot file missing: ${snapshotPath}`);
98	    }
99	
100	    const synologyUser = loadToken("synology_username");
101	    const synologyPass = loadToken("synology_password");
102	    if (!synologyUser || !synologyPass) {
103	      throw new Error("Synology credentials not configured. Please open Settings.");
104	    }
105	
106	    const synologyConfig = {
107	      url: job.synologyUrl ?? "",
108	      port: job.synologyPort,
109	      username: synologyUser,
110	      password: synologyPass,
111	    };
112	
113	    const remoteDir = dirname(job.relativePath).replace(/^[^/\\]+[/\\]/, "");
114	    const shareName = job.relativePath.split("/")[0] ?? job.relativePath.split("\\")[0];
115	    const tempName = job.filename + job.tempSuffix;
116	
117	    await uploadFile(
118	      synologyConfig,
119	      snapshotPath,
120	      shareName,
121	      remoteDir,
122	      tempName,
123	      job.filename,
124	      (progress) => progressCallback?.(checkoutId, progress.percent),
125	    );
126	
127	    const finalHash = await sha256File(snapshotPath);
128	    const finalSize = statSync(snapshotPath).size;
129	
130	    await completeCheckin({
131	      checkout_id: checkoutId,
132	      final_hash: finalHash,
133	      final_size: finalSize,
134	      upload_method: "synology_file_station",
135	      synology_upload_user: synologyUser,
136	      source_provider: job.sourceProvider,
137	      source_version: job.seafileObjId ?? null,
138	    });
139	
140	    removeJob(checkoutId);
141	    progressCallback?.(checkoutId, 100);
142	    log.info(`Upload complete for checkout ${checkoutId}`);
143	  } catch (e: unknown) {
144	    const msg = e instanceof Error ? e.message : String(e);
145	    log.error(`Upload failed for checkout ${checkoutId}:`, msg);
146	
147	    const retryCount = job.retryCount + 1;
148	    if (retryCount >= UPLOAD_MAX_RETRIES) {
149	      updateJob(checkoutId, { status: "failed", retryCount });
150	    } else {
151	      updateJob(checkoutId, { status: "pending", retryCount });
152	      await sleep(UPLOAD_RETRY_DELAY_MS * retryCount);
153	    }
154	  }
155	}
156	
157	function updateJob(checkoutId: string, updates: Partial<StoredJob>): void {
158	  const jobs = readJobs();
159	  const idx = jobs.findIndex((j) => j.checkoutId === checkoutId);
160	  if (idx >= 0) {
161	    jobs[idx] = { ...jobs[idx], ...updates };
162	    writeJobs(jobs);
163	  }
164	}
165	
166	function removeJob(checkoutId: string): void {
167	  const jobs = readJobs().filter((j) => j.checkoutId !== checkoutId);
168	  writeJobs(jobs);
169	}
170	
171	export function getPendingJobs(): { checkoutId: string; status: string; retryCount: number }[] {
172	  return readJobs().map((j) => ({
173	    checkoutId: j.checkoutId,
174	    status: j.status,
175	    retryCount: j.retryCount,
176	  }));
177	}
178	
179	function sleep(ms: number): Promise<void> {
180	  return new Promise((resolve) => setTimeout(resolve, ms));
181	}
