353	// ── File watcher ──────────────────────────────────────────────────────────────
354	
355	function watchFile(checkoutId: string, filePath: string): void {
356	  if (!existsSync(filePath)) return;
357	  stopWatcher(checkoutId);
358	
359	  const watcher = chokidar.watch(filePath, {
360	    persistent: true,
361	    ignoreInitial: true,
362	    awaitWriteFinish: { stabilityThreshold: 2000, pollInterval: 300 },
363	  });
364	
365	  watcher.on("change", () => {
366	    const record = active.get(checkoutId);
367	    if (!record) return;
368	    log.debug(`File changed: ${filePath}`);
369	    notify();
370	  });
371	
372	  watcher.on("unlink", () => {
373	    const record = active.get(checkoutId);
374	    if (!record) return;
375	    record.errorMessage = "Workspace file was deleted.";
376	    updateStatus(checkoutId, "error");
377	  });
378	
379	  watchers.set(checkoutId, watcher);
380	}
381	
382	function stopWatcher(checkoutId: string): void {
383	  const w = watchers.get(checkoutId);
384	  if (w) {
385	    w.close();
386	    watchers.delete(checkoutId);
387	  }
388	}
