1154	  let afterId: string | null = null;
1155	  let totalScanned = 0;
1156	  let totalCleared = 0;
1157	
1158	  const worker = await createCompatAuditWorker();
1159	  try {
1160	    while (true) {
1161	      const { assets, batch_size } = await api.getCompatAuditBatch(afterId);
1162	      if (!assets || assets.length === 0) break;
1163	
1164	      const badIds: string[] = [];
1165	
1166	      for (const asset of assets) {
1167	        totalScanned++;
1168	        if (!asset.thumbnail_url) continue;
1169	        const isPlaceholder = await isCompatAlertThumbnail(asset.thumbnail_url, worker);
1170	        if (isPlaceholder) {
1171	          badIds.push(asset.id);
1172	          logger.info("Compat audit: flagging placeholder thumbnail", { path: asset.relative_path });
1173	        }
1174	      }
1175	
1176	      if (badIds.length > 0) {
1177	        await api.clearCompatThumbnails(badIds);
1178	        totalCleared += badIds.length;
1179	        logger.info("Compat audit: cleared placeholder thumbnails", { cleared: badIds.length, cumulative: totalCleared });
1180	      }
1181	
1182	      if (assets.length < batch_size) break; // last page
1183	      afterId = assets[assets.length - 1].id;
1184	    }
1185	
1186	    logger.info("Compat thumbnail audit complete", { scanned: totalScanned, cleared: totalCleared });
1187	    await api.completeCompatAudit(totalScanned, totalCleared);
1188	  } catch (e) {
